<?php if (!defined('BASEPATH'))    exit('No direct script access allowed');class Auth{    public $CI;	    public function is_login()	{		$this->CI = & get_instance();		$class 		= strtolower($this->CI->router->fetch_class());				$x 			= $this->is_logged_in();		$view 		= $this->CI->router->fetch_method();		switch(strtolower($class))		{			case 'Superadmin_controller': case 'admin_controller':				if(in_array($view, array("login")) && $x)				{					redirect(site_url('user/dashboard'));				}								if( !in_array($view, array("index", "forgot_password")) && !$x && !$this->CI->input->is_ajax_request() )				{					redirect(site_url('user/login'));				}					# for ajax request				if( !$x &&  $this->CI->input->is_ajax_request() )				{					echo json_encode(array('status'=>'0', 'msg'=>'You are no longer logged in. Login again.'));					exit(0);				}			break;		}    }		private function is_logged_in()	{		$this->CI->load->library('session');		$this->CI->load->library('user_agent');		$user = $this->CI->session->userdata('logged_in');		if ($user == "") { return false; } else { return true; }	}	}